const body = $json.body ?? $json;
const env = typeof $env === "undefined" ? {} : $env;
const faq = [{"number":1,"question":"What are the credentials needed for the registration on the iAMS Mobile App?","answer":"Choose Acsys Mobile iAMS from the available list. Click Select Cloud and choose Custom, switch the tab to https and enter below details. Click register, OTP will be received enter it, enter your Password, and click register you’ll be registered successfully.\nKindly input these details:\nCloud ID: ftaprelay.frontiertowersphilippines.com\nServer ID: ftapiams\nUse registered email address."},{"number":2,"question":"What is the PIN Code on the iAMS Mobile App?","answer":"1234"},{"number":3,"question":"Where to message if there is a need for an emergency access?","answer":"Strictly for Direct Messages Only\n∙  FTAP Site Access No.:  09177149799 (WhatsApp)\n∙  FTAP Site Access No.:  09992293099 (WhatsApp)"},{"number":4,"question":"Where to call if there is a need of an emergency access after office hours, weekends, and holidays?","answer":"∙  Site Access Landline No. - (02) 82504659\n∙  Site Access Globe Hotline No. - 180015500101"},{"number":5,"question":"What should we do if we receive an error of “No Access Right on specified Asset Point”","answer":"Kindly check first if your ticket has been approved and if the registered personnel’s area of responsibility has been updated on the User’s geography.\nIf all these are correct and issue persist, kindly coordinate with the FTAP WhatsApp hotline and send the screenshot."},{"number":6,"question":"Where to send inquiries, requests, or escalations?","answer":"For GLOBE customers:  globesiteaccess@frontiertowersphilippines.com"},{"number":7,"question":"How to add vendor organization on iAMS Web Portal?","answer":"Kindly email us the details of the vendor organization.\nFor Add Organization,\nPlease fill the details below:\nVendor Name:\nVendor Contact Person:\nVendor Email:\nVendor Contact Number:"},{"number":8,"question":"What to do if tickets cannot be found on the ticket list or on the iAMS web portal?","answer":"Re-file or create another work order/ticket number and email us for approval."},{"number":9,"question":"Who to call if the site as an issue with the lessor?","answer":"FTAP Estate Management\n•   North NCR and North Luzon: 0905 558 0676\n•   South NCR and South Luzon: 0998 571 5446\n•   Visayas Area: 0968 897 2421\n•   Mindanao Area: 0961 709 3036"},{"number":10,"question":"What to do if we need to use the ticket again for the access?","answer":"Kindly remind the team to uncheck the “CLOSE TICKET” box. Afterwards, go to Menu > Ticket list, and click “REOPEN” so that they can reuse the ticket until its validity date. Maximum validity of access ticket is 10 days. Request a new ticket access if the activity would go beyond the 10 days."},{"number":11,"question":"What do we need to upload on the shared OneDrive?","answer":"For new registration:\n-      Company ID\n-      Working at Height certificate (WAH)\n-      Certificate of Employment (COE)\n-      NBI Clearance\nFor access request:\n-      MOP/SOW (Detailed information of activity)\n-      RAAWA (Globe)"},{"number":12,"question":"Why can’t we request access for installation and dismantling activities?","answer":"You need to provide the approved change request application number."},{"number":13,"question":"Why can't we request access for pullout activities?","answer":"Fill out the FTAP Extraction Form, complete all details and have it signed to your authorized signatories. Email the form to Site Access Team and they will route it for approval internally. Once approved, you may now file for work order/ticket access."},{"number":14,"question":"What should we do if we receive an error of “Not Able to Connect on Relay Server” or “Server is Busy”?","answer":"Kindly check if you’re using the new mobile application.\nIf all these are correct and issue persist, kindly coordinate with the FTAP WhatsApp hotline and send the screenshot for further analysis."},{"number":15,"question":"What should we do if we receive an error of \"Check-in successful for asset point. Asset point already opened. Please proceed to work\"","answer":"Kindly coordinate with the FTAP WhatsApp hotline and send the screenshot for further analysis."},{"number":16,"question":"What should we do if we receive an error of \" Could not able to find Access Point - Try again\"","answer":"Kindly coordinate with the FTAP WhatsApp hotline and send the screenshot for further analysis."},{"number":17,"question":"What should we do if we receive an error of \" The previous site not close yet, cannot request another site before closing it\"","answer":"Kindly coordinate with the FTAP WhatsApp hotline and send the screenshot for further analysis."}];
const source = {"title":"FTAP Site Access Management System FAQs","sourceDocument":"3. FTAP SAM System FAQs. 2025 (GLOBE).pdf","audience":"GLOBE customers","effectiveDate":"January 2026"};

function firstDefined(...values) {
  return values.find((value) => value !== undefined && value !== null && String(value).trim() !== "");
}

function normalize(value) {
  return String(value ?? "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const stopWords = new Set(["a", "an", "and", "are", "as", "do", "for", "how", "if", "is", "it", "of", "on", "or", "that", "the", "this", "to", "we", "what", "when", "where", "who", "why", "with"]);
const inScopeTokens = new Set(["access", "acsys", "app", "approval", "approved", "area", "asset", "busy", "certificate", "check", "checkin", "clearance", "cloud", "coe", "code", "company", "connect", "credentials", "dismantling", "email", "emergency", "employment", "escalations", "extraction", "find", "ftap", "geography", "globe", "hotline", "iams", "inquiries", "installation", "landline", "lessor", "mobile", "mop", "nbi", "onedrive", "organization", "otp", "password", "pin", "portal", "pullout", "raawa", "registration", "relay", "reopen", "requests", "server", "site", "sow", "ticket", "upload", "vendor", "wah", "whatsapp", "work"]);
const inScopePhrases = ["after office", "asset point", "check in", "check-in", "close ticket", "could not able to find", "no access right", "not able to connect", "previous site", "server is busy", "specified asset point", "ticket list", "work order"];

function tokenize(value) {
  return normalize(value)
    .split(" ")
    .filter((token) => token.length > 1 && !stopWords.has(token));
}

function scoreEntry(question, entry) {
  const queryTokens = tokenize(question);
  const haystack = new Set(tokenize(entry.question + " " + entry.answer));
  const titleTokens = new Set(tokenize(entry.question));
  let score = 0;

  for (const token of queryTokens) {
    if (haystack.has(token)) score += titleTokens.has(token) ? 3 : 1;
  }

  const haystackText = normalize(entry.question + " " + entry.answer);
  const normalizedQuestion = normalize(question);
  if (normalizedQuestion === normalize(entry.question)) score += 100;
  if (normalizedQuestion.includes("pin") && normalize(entry.question).includes("pin")) score += 6;
  if (normalizedQuestion.includes("emergency") && haystackText.includes("emergency")) score += 4;
  if (normalizedQuestion.includes("whatsapp") && haystackText.includes("whatsapp")) score += 4;
  if (normalizedQuestion.includes("no access right") && entry.number === 5) score += 30;
  if (normalizedQuestion.includes("specified asset point") && entry.number === 5) score += 30;
  if (normalizedQuestion.includes("onedrive") && haystackText.includes("onedrive")) score += 5;
  if (normalizedQuestion.includes("relay") && haystackText.includes("relay")) score += 5;
  if (normalizedQuestion.includes("not able to connect") && entry.number === 14) score += 30;
  if (normalizedQuestion.includes("server is busy") && entry.number === 14) score += 30;
  if (normalizedQuestion.includes("lessor") && haystackText.includes("lessor")) score += 5;
  if (normalizedQuestion.includes("reopen") && haystackText.includes("reopen")) score += 5;
  if (normalizedQuestion.includes("pullout") && haystackText.includes("pullout")) score += 5;
  if (normalizedQuestion.includes("installation") && haystackText.includes("installation")) score += 5;
  if (normalizedQuestion.includes("dismantling") && haystackText.includes("dismantling")) score += 5;

  return { entry, score, queryTokenCount: Math.max(queryTokens.length, 1) };
}

function isInScopeQuestion(question) {
  const normalizedQuestion = normalize(question);
  if (!normalizedQuestion) return false;
  if (faq.some((entry) => normalize(entry.question) === normalizedQuestion)) return true;
  if (faq.some((entry) => normalizedQuestion === String(entry.number) || normalizedQuestion === "faq " + entry.number)) return true;
  if (inScopePhrases.some((phrase) => normalizedQuestion.includes(phrase))) return true;
  return tokenize(normalizedQuestion).some((token) => inScopeTokens.has(token));
}

const question = String(firstDefined(body.message, body.question, body.text, body.prompt, "")).trim();
const sessionId = String(firstDefined(body.sessionId, body.session_id, body.conversationId, "maui-demo"));
const topMatches = faq
  .map((entry) => scoreEntry(question, entry))
  .sort((a, b) => b.score - a.score)
  .slice(0, 3);

const best = topMatches[0];
const confidence = question && best ? Math.min(0.98, Number((best.score / Math.max(best.queryTokenCount * 3, 1)).toFixed(2))) : 0;
const hasAnswer = Boolean(question && best && best.score > 0 && isInScopeQuestion(question));
const fallbackAnswer = "I can only answer questions covered by the FTAP SAM FAQ knowledge base. Please ask about iAMS registration, PIN, emergency access, tickets, OneDrive uploads, relay/server errors, lessor/site access, or other FTAP site access FAQ topics.";
const localAnswer = hasAnswer ? best.entry.answer : fallbackAnswer;
const suggestions = faq.slice(0, 5).map((entry) => entry.question);
const useOpenAI = Boolean(env.OPENAI_API_KEY && !String(env.OPENAI_API_KEY).startsWith("sk-replace"));

const context = topMatches
  .filter((match) => hasAnswer && match.score > 0)
  .map((match) => ({
    number: match.entry.number,
    question: match.entry.question,
    answer: match.entry.answer,
    score: match.score
  }));

const response = {
  sessionId,
  answer: localAnswer,
  confidence,
  source: "local-faq",
  matchedFaq: hasAnswer ? {
    number: best.entry.number,
    question: best.entry.question,
    score: best.score
  } : null,
  citations: context.map((match) => ({
    number: match.number,
    question: match.question
  })),
  suggestedQuestions: hasAnswer ? [] : suggestions,
  generatedAt: new Date().toISOString()
};

const openAiRequest = {
  model: env.OPENAI_MODEL || "gpt-4o-mini",
  instructions: [
    "You are an FTAP Site Access FAQ assistant for GLOBE users.",
    "Use only the supplied FAQ context to identify the best matching FAQ item.",
    "Return a concise confirmation of the FAQ number and do not add procedures, contacts, credentials, or ticket rules.",
    "The workflow will return the exact PDF answer text from the matched FAQ item; do not rewrite the answer."
  ].join("\n"),
  input: [
    {
      role: "user",
      content: [
        {
          type: "input_text",
          text: JSON.stringify({
            question,
            source,
            faq_context: context,
            local_fallback_answer: localAnswer
          })
        }
      ]
    }
  ],
  temperature: 0.1,
  max_output_tokens: 500
};

return [{
  json: {
    question,
    sessionId,
    response,
    useOpenAI: useOpenAI && hasAnswer,
    openAiRequest,
    faqContext: context
  }
}];

const base = $("Find FAQ Answer").first().json;
const response = $input.first().json;

function getText(resp) {
  if (typeof resp?.output_text === "string") return resp.output_text;
  if (Array.isArray(resp?.output)) {
    for (const output of resp.output) {
      if (Array.isArray(output?.content)) {
        for (const content of output.content) {
          if (typeof content?.text === "string") return content.text;
        }
      }
    }
  }
  if (typeof resp?.choices?.[0]?.message?.content === "string") {
    return resp.choices[0].message.content;
  }
  return "";
}

const modelAnswer = response?.error ? "" : getText(response).trim();
const errorMessage = response?.error?.message || "";

return [{
  json: {
    ...base,
    openAiRaw: response,
    response: {
      ...base.response,
      answer: base.response.answer,
      source: modelAnswer ? "openai-grounded-faq-exact" : "local-faq",
      openAi: {
        used: Boolean(modelAnswer),
        mode: "route-only-exact-pdf-answer",
        error: errorMessage
      }
    }
  }
}];
